const main = require('../../lib/jibo-emotion-system');
let AppraisalSystem = main.appraisal.AppraisalSystem;
let SensorySystem = main.sensing.SensorySystem;
const EmotionSystem = main.emotionSystem.EmotionSystem;

let ASRTextInputRule = main.appraisal.rules.ASRTextInputRule;
let TouchRule = main.appraisal.rules.TouchRule;
let MimRule = main.appraisal.rules.MimRule;
let IdentityRule = main.appraisal.rules.IdentityRule;
let TouchSensor = main.sensing.sensors.TouchSensor;
let ASRInputSensor = main.sensing.sensors.ASRInputSensor;
let MimSensor = main.sensing.sensors.MimSensor;
let IdentitySensor = main.sensing.sensors.IdentitySensor;
let TouchTypes = main.common.TouchTypes;

const jibo = require('../../../jibo');
let es;

describe('AppraisalSystem', () => {

    beforeEach((done) => {
        es = new EmotionSystem();
        es.init({
            jibo: jibo
        }).then(done);
    });

    afterEach(() => {
        es.dispose();
    });


    describe('#subscribe', () => {

        it('should support text sentiment analysis.', () => {
            let spy = sinon.spy();
            const txtSensor = new ASRInputSensor(es);
            const sensorySystem = new SensorySystem(es);
            sensorySystem.init([
                txtSensor
            ]);
            const asrRule = new ASRTextInputRule('ASRTextInputRule', es);
            asrRule.init(sensorySystem);
            const appraisalSystem = new AppraisalSystem(es);
            appraisalSystem.init([
                asrRule
            ]);
            appraisalSystem.events.impactTriggered.on((emotionTrace) => {
                spy(emotionTrace.emotionalImpact);
            });
            let UNDESIRABLE_TEXT = 'you suck, jibo';
            txtSensor.supplyData(UNDESIRABLE_TEXT);
            let resultA = spy.getCall(0).args[0];
            expect(resultA.valence < 0).to.be.true;
            let DESIRABLE_TEXT = 'i love you, jibo';
            txtSensor.supplyData(DESIRABLE_TEXT);
            let resultB = spy.getCall(1).args[0];
            expect(resultB.valence > 0).to.be.true;
            let ABIGUOUS_TEXT = 'i love you, idiot jibo';
            txtSensor.supplyData(ABIGUOUS_TEXT);
            let resultC = spy.getCall(2).args[0];
            expect(resultC.valence === 0).to.be.true;
            appraisalSystem.dispose();
            sensorySystem.dispose();
        });

        it('should support touch events.', function(done) {
            sinon.stub(jibo.action, 'addPlayAnimationGoal', function(data) {
                jibo.action.addPlayAnimationGoal.restore()
                expect(data.category).to.equal('Touch');
                sensorySystem.dispose();
                done();
            });
            let spy = sinon.spy();
            const touchSensor = new TouchSensor(es);
            const sensorySystem = new SensorySystem(es);
            sensorySystem.init([
                touchSensor
            ]);
            const touchRule = new TouchRule('TouchRule', es);
            touchRule.init(sensorySystem);
            es._appraisalSystem.events.impactTriggered.on((emotionalImpact) => {
                spy(emotionalImpact.emotionalImpact);
            });
            // Simulate a touch...make sure jibo's emotions move.
            es.triggerTouch({
                type: TouchTypes.HEAD_RIGHT
            });

            let resultA = spy.getCall(0).args[0];
            expect(resultA.valence).to.equal(0.2);
            expect(resultA.confidence).to.equal(0.1);
        });

        it('should support MIM error events.', () => {
            let spy = sinon.spy();
            const mimSensor = new MimSensor(es);
            const sensorySystem = new SensorySystem(es);
            sensorySystem.init([
                mimSensor
            ]);
            const mimRule = new MimRule('MimRule', es);
            mimRule.init(sensorySystem);
            const appraisalSystem = new AppraisalSystem(es);
            appraisalSystem.init([
                mimRule
            ]);
            appraisalSystem.events.impactTriggered.on((emotionalImpact) => {
                spy(emotionalImpact.emotionalImpact);
            });
            // Simulate a MIM error.
            mimSensor.supplyData({});
            let resultA = spy.getCall(0).args[0];
            expect(resultA.valence).to.equal(0);
            expect(resultA.confidence).to.equal(-1);
            sensorySystem.dispose();
            appraisalSystem.dispose();
        });

        it('should support ID events.', () => {
            let spy = sinon.spy();
            const idSensor = new IdentitySensor(es);
            const sensorySystem = new SensorySystem(es);
            sensorySystem.init([
                idSensor
            ]);
            const idRule = new IdentityRule('IdentityRule', es);
            idRule.init(sensorySystem);
            const appraisalSystem = new AppraisalSystem(es);
            appraisalSystem.init([
                idRule
            ]);
            appraisalSystem.events.impactTriggered.on((emotionalImpact) => {
                spy(emotionalImpact.emotionalImpact);
            });
            // Simulate a MIM error.
            idSensor.supplyData("PRESENCE_STARTED");
            let resultA = spy.getCall(0).args[0];
            console.log(resultA);
            expect(resultA.valence).to.equal(0.01);
            expect(resultA.confidence).to.equal(0.01);
            sensorySystem.dispose();
            appraisalSystem.dispose();
        });

    });

});
